function create_field( $field ) {
    // defaults?
    $field = array_merge( isset( $this->defaults ) ? $this->defaults : array(), $field );

    $syntax_highlight = false;

    if ( isset( $field['syntax-highlight'] ) && $field['syntax-highlight'] === '1' ) {
        $syntax_highlight = true;
        wp_enqueue_script( 'highlightjs' );
    }

    $id          = 'editor_' . uniqid();
