 *
 * @param array       $args     Field arguments.
 * @param LP_Question $question The question object.
 *
 * @return string
 */
function learn_press_field_question_duration( $args = array(), $question = null ) {
	global $post;

	if ( null === $question ) {
		return '';
	}

	$question_id   = isset( $question->id ) ? $question->id : 0;
	$duration_type = get_post_meta( $post->ID, '_lp_duration_type', true );
	$value         = get_post_meta( $question_id, '_question_duration', true );

	$wrap_class = 'learn-press-question-duration';

	if ( 'questions_duration' !== $duration_type ) {
		$wrap_class .= ' hide';
	}

	$args = wp_parse_args(
		$args,
		array(
			'name'        => 'learn_press_question[' . $question_id . '][duration]',
			'id'          => 'learn-press-question-duration-' . $question_id,
			'class'       => 'learn-press-question-duration',
			'selected'    => '',
			'echo'        => true,
			'value'       => 0,
			'step'        => 1,
			'min'         => 0,
			'placeholder' => __( 'Minutes', 'learnpress' ),
		)
	);

	$args['value'] = $value;

	if ( ! $args['id'] ) {
		$args['id'] = $args['name'];
	}

	$input_id = empty( $args['clone'] ) ? $args['id'] : '';

	$output  = '<span class="' . esc_attr( $wrap_class ) . '">';
	$output .= '<label class="screen-reader-text" for="' . esc_attr( $input_id ) . '">' . esc_html__( 'Duration (Minutes)', 'learnpress' ) . '</label>';
	$output .= sprintf(
		'<input type="number" class="%s" name="%s" id="%s" value="%s" step="%s" min="%s" max="%s" placeholder="%s"/>',
		esc_attr( $args['class'] ),
		esc_attr( $args['name'] ),
		esc_attr( $input_id ),
		esc_attr( $args['value'] ),
		esc_attr( $args['step'] ),
		esc_attr( $args['min'] ),
		esc_attr( ! empty( $args['max'] ) ? $args['max'] : '' ),
		esc_attr( $args['placeholder'] )
	);
	$output .= '</span>';

	return $output;
}

