    $table_file = WPOPT_SUPPORTERS . '/activity-log/ActivityLog_Table.class.php';
    if ( ! file_exists( $table_file ) ) {
        return;
    }
    require_once $table_file;

    $table = new ActivityLog( array( 'action_hook' => $this->action_hook, 'settings' => $this->option() ) );
    $table->prepare_items();

    $current_page = isset( $_GET['page'] ) ? sanitize_text_field( wp_unslash( $_GET['page'] ) ) : '';
    ?>
