/**
 * Update a WP Super Cache setting in the config file and global scope.
 *
 * @since 1.0
 * @param string $field The config variable name to update.
 * @param mixed  $value The new value.
 * @return bool True on success, false on failure or disallowed field.
 */
function wp_cache_setting( $field, $value ) {
	global $wp_cache_config_file;

	$allowed_fields = array(
		'cache_enabled', 'super_cache_enabled', 'cache_compression', 'cache_max_time',
		'cache_rebuild_files', 'wp_cache_mobile', 'wp_cache_no_cache_for_get',
		'wp_cache_clear_on_post_edit', 'cache_rejection_uris', 'cache_accepted_uris',
		'wp_cache_mobile_browsers', 'wp_cache_mobile_prefixes', 'wp_cache_mod_rewrite',
		'wp_supercache_304', 'wp_cache_refresh_single_only', 'wp_cache_make_known_anon',
		'wp_cache_mutex_disabled', 'wp_super_cache_debug', 'wp_cache_debug_level',
		'wp_cache_debug_to_file', 'wp_cache_debug_log', 'wp_cache_debug_ip',
		'cache_scheduled_time', 'cache_schedule_interval', 'cache_gc_email_me',
	);

	if ( ! in_array( $field, $allowed_fields, true ) ) {
		return false;
	}

	if ( ! current_user_can( 'manage_options' ) ) {
		return false;
	}

	$GLOBALS[ $field ] = $value;
	$safe_field        = preg_quote( $field, '/' );

	if ( is_numeric( $value ) ) {
		return wp_cache_replace_line( '^ *\$' . $safe_field, "\${$field} = {$value};", $wp_cache_config_file );
	} elseif ( is_bool( $value ) ) {
		$output_value = $value === true ? 'true' : 'false';
		return wp_cache_replace_line( '^ *\$' . $safe_field, "\${$field} = {$output_value};", $wp_cache_config_file );
	} elseif ( is_object( $value ) || is_array( $value ) ) {
		$text = var_export( $value, true ); // phpcs:ignore WordPress.PHP.DevelopmentFunctions.error_log_var_export
		$text = preg_replace( '/[\s]+/', ' ', $text );
		return wp_cache_replace_line( '^ *\$' . $safe_field, "\${$field} = {$text};", $wp_cache_config_file );
	} else {
		$safe_value = addslashes( (string) $value );
		return wp_cache_replace_line( '^ *\$' . $safe_field, "\${$field} = '{$safe_value}';", $wp_cache_config_file );
	}
}

