/**
 * Count products within certain terms, taking the main WP query into consideration.
 *
 * @param  array  $term_ids   Term IDs.
 * @param  string $taxonomy   Taxonomy.
 * @param  string $query_type Query type.
 * @return array
 */
function get_filtered_term_product_counts( $term_ids, $taxonomy, $query_type = 'and' ) {
		global $wpdb;

		$term_ids   = array_map( 'absint', $term_ids );
		$tax_query  = WC_Query::get_main_tax_query();
		$meta_query = WC_Query::get_main_meta_query();

		if ( 'or' === $query_type ) {
			foreach ( $tax_query as $key => $query ) {
				if ( is_array( $query ) && $taxonomy === $query['taxonomy'] ) {
					unset( $tax_query[ $key ] );
				}
			}
		}

		$meta_query     = new WP_Meta_Query( $meta_query );
		$tax_query      = new WP_Tax_Query( $tax_query );
		$meta_query_sql = $meta_query->get_sql( 'post', $wpdb->posts, 'ID' );
		$tax_query_sql  = $tax_query->get_sql( $wpdb->posts, 'ID' );

		if ( empty( $term_ids ) ) {
			return array();
		}

		$placeholders = implode( ',', array_fill( 0, count( $term_ids ), '%d' ) );

		$query = $wpdb->prepare(
			"SELECT term_taxonomy_id, COUNT( DISTINCT {$wpdb->posts}.ID ) AS post_count
			 FROM {$wpdb->posts}
			 INNER JOIN {$wpdb->term_relationships} ON ( {$wpdb->posts}.ID = {$wpdb->term_relationships}.object_id )
			 {$tax_query_sql['join']}
			 {$meta_query_sql['join']}
			 WHERE {$wpdb->posts}.post_type IN ( 'product', 'product_variation' )
			 AND {$wpdb->posts}.post_status = 'publish'
			 {$tax_query_sql['where']}
			 {$meta_query_sql['where']}
			 AND {$wpdb->term_relationships}.term_taxonomy_id IN ( {$placeholders} )
			 GROUP BY term_taxonomy_id",
			$term_ids
		);

		$results = $wpdb->get_results( $query ); // phpcs:ignore WordPress.DB.PreparedSQL.NotPrepared

		$counts = array();
		if ( $results ) {
			foreach ( $results as $row ) {
				$counts[ $row->term_taxonomy_id ] = absint( $row->post_count );
