/**
	 * Gets the animation stylesheet, as inline CSS.
	 *
	 * @since 1.0.0
	 *
	 * @param string               $alias Optional. Slug or alias to reference the animation with.
	 * @param array<string, mixed> $args  Optional. Animation arguments.
	 * @return string Animation stylesheet, as inline CSS, or empty string if none.
	 */
public function get_stylesheet( string $alias = '', array $args = array() ): string {
	static $cache = array();

	$cache_key = $this->slug . '|' . $alias;
	if ( isset( $cache[ $cache_key ] ) ) {
		return $cache[ $cache_key ];
	}

	$css = '';
	if ( (bool) $this->use_stylesheet ) {
		$stylesheet_path = $this->use_stylesheet;
		if ( ! is_string( $stylesheet_path ) ) {
			$stylesheet_path = plvt_get_asset_path( "css/view-transition-animation-{$this->slug}.css" );
		}

		// Validate path stays within plugin directory.
		$plugin_base = realpath( plugin_dir_path( __FILE__ ) );
		$real_path   = realpath( $stylesheet_path );
		if ( false === $real_path || false === $plugin_base || strpos( $real_path, $plugin_base ) !== 0 ) {
			return '';
		}

		// phpcs:ignore WordPress.WP.AlternativeFunctions.file_get_contents_file_get_contents
		$css = file_get_contents( $real_path );
		if ( false === $css || '' === $css ) {
			return '';
		}
	}

	$cache[ $cache_key ] = $css;
	return $css;
}

