/**
	 * Normalizes analytics section input into reports and report configs.
	 *
	 * @since 1.170.0
	 *
	 * @param mixed $section_data Section payload.
	 * @return array Normalized analytics section input as array( $reports, $report_configs ).
	 */
public function normalize_section_input( $section_data ) {
	$reports        = array();
	$report_configs = array();

	if ( is_object( $section_data ) ) {
		$section_data = (array) $section_data;
	}

	if ( ! is_array( $section_data ) ) {
		return array( $reports, $report_configs );
	}

	if ( $this->is_sequential_array( $section_data ) ) {
		foreach ( $section_data as $item ) {
			if ( ! is_array( $item ) ) {
				continue;
			}
			// Separate report configs (keyed 'config') from report data.
			if ( isset( $item['config'] ) && is_array( $item['config'] ) ) {
				$report_configs[] = $item['config'];
				unset( $item['config'] );
			}
			$reports[] = $item;
		}
	} else {
		if ( isset( $section_data['config'] ) && is_array( $section_data['config'] ) ) {
			$report_configs[] = $section_data['config'];
			unset( $section_data['config'] );
		}
		$reports[] = $section_data;
	}

	return array( $reports, $report_configs );
}

