		if ( ! taxonomy_exists( $taxonomy ) ) {
			return array();
		}

		$term_ids = array_map( 'absint', (array) $term_ids );

		$cache_key  = 'masvideo_term_counts_' . md5( implode( ',', $term_ids ) . $taxonomy . $query_type );
		$cached     = wp_cache_get( $cache_key, 'masvideos' );

		if ( false !== $cached ) {
			return $cached;
		}

		$tax_query  = MasVideos_TV_Shows_Query::get_main_tax_query();
		$meta_query = MasVideos_TV_Shows_Query::get_main_meta_query();

		if ( 'or' === $query_type ) {
			foreach ( $tax_query as $key => $tax_item ) {
				if ( is_array( $tax_item ) && $taxonomy === $tax_item['taxonomy'] ) {
					unset( $tax_query[ $key ] );
				}
			}
		}

		$meta_query     = new WP_Meta_Query( $meta_query );
		$tax_query      = new WP_Tax_Query( $tax_query );
		$meta_query_sql = $meta_query->get_sql( 'post', $wpdb->posts, 'ID' );
