function get_totalauthors( $display = true ) {
	$cached = wp_cache_get( 'get_totalauthors', 'wp-stats' );

	if ( false !== $cached ) {
		$totalauthors = (int) $cached;
	} else {
		global $wpdb;
		$totalauthors = (int) $wpdb->get_var(
			$wpdb->prepare(
