/**
 * AJAX handler to upload an image to Polldaddy.
 *
 * @since 1.0.0
 * @return void
 */
public function ajax_upload_image() {
		$client_path = plugin_dir_path( __FILE__ ) . 'polldaddy-client.php';
		if ( ! file_exists( $client_path ) ) {
			wp_die( -1 );
		}
		require_once $client_path;

		check_admin_referer( 'send-media' );

		if ( ! current_user_can( 'upload_files' ) ) {
			wp_die( -1 );
		}

		$attach_id = isset( $_POST['attach-id'] ) ? absint( $_POST['attach-id'] ) : 0;
		$media_id  = isset( $_POST['media-id'] ) ? absint( $_POST['media-id'] ) : 0;
		$user_code = isset( $_POST['uc'] ) ? sanitize_text_field( wp_unslash( $_POST['uc'] ) ) : '';
		$url       = isset( $_POST['url'] ) ? esc_url_raw( wp_unslash( $_POST['url'] ) ) : '';

		$parts = pathinfo( $url );
		$name  = preg_replace( '/\?.*/', '', $parts['basename'] );

		$polldaddy = new api_client( WP_POLLDADDY__PARTNERGUID, $user_code );
		$data      = '';

		if ( function_exists( 'is_private_blog' ) && is_private_blog() ) {
			$file_path = get_attached_file( $attach_id );
			if ( $file_path && 0 === validate_file( $file_path ) ) {
				global $wp_filesystem;
				WP_Filesystem();
				$data = base64_encode( $wp_filesystem->get_contents( $file_path ) );
			}
		}

		$response = $polldaddy->upload_image( $name, $url, 'poll', ( $media_id > 1000 ? $media_id : 0 ), $data );

		if ( is_a( $response, 'PollDaddy_Media' ) ) {
			echo esc_url( urldecode( $response->upload_result ) ) . '||' . absint( $media_id );
		}
		die();
	}

