/**
	 * Dispatch an internal REST API request from Integromat connector.
	 *
	 * Requires a valid nonce passed as the X-WP-Nonce header to authenticate the request.
	 *
	 * @return void
	 */
function dispatch() {
		$nonce = isset( $_SERVER['HTTP_X_WP_NONCE'] ) ? sanitize_key( wp_unslash( $_SERVER['HTTP_X_WP_NONCE'] ) ) : '';
		if ( ! wp_verify_nonce( $nonce, 'wp_rest' ) ) {
			wp_die( esc_html__( 'Invalid nonce.', 'integromat-connector' ), '', array( 'response' => 403 ) );
		}

		$request_uri = isset( $_SERVER['REQUEST_URI'] ) ? $_SERVER['REQUEST_URI'] : '';
		preg_match( '#\/wp-json/(.*)\??.*#i', $request_uri, $route_match );
		if ( ! isset( $route_match[1] ) ) {
			return;
		}
		$f          = explode( '?', $route_match[1] );
		$rest_route = '/' . $f[0];

		$method  = isset( $_SERVER['REQUEST_METHOD'] ) ? sanitize_key( wp_unslash( $_SERVER['REQUEST_METHOD'] ) ) : 'GET';
		$request = new \WP_REST_Request( $method, $rest_route );
		$request->set_query_params( $_GET );

		$body = null;
		if ( 'POST' === $method ) {
			$body = json_decode( file_get_contents( 'php://input' ), true );
			if ( is_array( $body ) ) {
				$request->set_body_params( $body );
			}

			if ( ! empty( $_FILES['file'] ) ) {
				self::upload_media();
			}
		}

		$response      = rest_do_request( $request );
		$server        = rest_get_server();
		$response_data = $server->response_to_data( $response, false );

		if ( 'POST' === $method && is_array( $body ) && ! empty( $body['meta'] ) ) {
			$content_type = self::get_content_type( $rest_route );
			self::update_meta( $response_data['id'], $content_type, $body['meta'] );
		}
		self::send_response( $response, $response_data );
	}

