/**
 * Determine the source file path from request context (env, header, or querystring).
 *
 * @param array $wod_options WebP on Demand options array.
 * @return string|false Absolute path to the source file, or false if not determined.
 */
function getSourceDocRoot( $wod_options = array() ) {
    // Check if it is in an environment variable.
    $source = self::getEnvPassedInRewriteRule( 'REQFN' );
    if ( $source !== false ) {
        self::$checking = 'source (passed through env)';
        return SanityCheck::absPathExistsAndIsFile( $source );
    }

    // Check if it is in header (but only if .htaccess was configured to send in header).
    if ( isset( $wod_options['base-htaccess-on-these-capability-tests'] ) ) {
        $cap_tests = $wod_options['base-htaccess-on-these-capability-tests'];
        $pass_through_header_unavailable = ( $cap_tests['passThroughHeaderWorking'] === false );
        $pass_through_env_available      = ( $cap_tests['passThroughEnvWorking'] === true );
        $header_magic_added_in_htaccess  = ( ! $pass_through_env_available ) && ( ! $pass_through_header_unavailable );
    } else {
        $header_magic_added_in_htaccess = true;
    }
    if ( $header_magic_added_in_htaccess && isset( $_SERVER['HTTP_REQFN'] ) ) {
        self::$checking = 'source (passed through request header)';
        $reqfn = SanityCheck::noControlChars( wp_unslash( $_SERVER['HTTP_REQFN'] ) );
        return SanityCheck::absPathExistsAndIsFile( $reqfn );
    }

    if ( ! isset( self::$docRoot ) ) {
        if ( isset( $_GET['root-id'] ) && isset( $_GET['xsource-rel-to-root-id'] ) ) {
            $xsrc_rel_to_root_id = SanityCheck::noControlChars( wp_unslash( $_GET['xsource-rel-to-root-id'] ) );
            $src_rel_to_root_id  = SanityCheck::pathWithoutDirectoryTraversal( substr( $xsrc_rel_to_root_id, 1 ) );
            $root_id = SanityCheck::noControlChars( wp_unslash( $_GET['root-id'] ) );
            SanityCheck::pregMatch( '#^[a-z]+$#', $root_id, 'Not a valid root-id' );
            $source = self::getRootPathById( $root_id ) . '/' . $src_rel_to_root_id;
            return SanityCheck::absPathExistsAndIsFile( $source );
        }
    }

    // Check querystring (relative path to docRoot) - when docRoot is available.
    if ( isset( self::$docRoot ) && isset( $_GET['xsource-rel'] ) ) {
        self::$checking = 'source (passed as relative path, through querystring)';
        $xsrc_rel = SanityCheck::noControlChars( wp_unslash( $_GET['xsource-rel'] ) );
        $src_rel  = SanityCheck::pathWithoutDirectoryTraversal( substr( $xsrc_rel, 1 ) );
        return SanityCheck::absPathExistsAndIsFile( self::$docRoot . '/' . $src_rel );
    }

    // Check querystring (full path) - only on Nginx.
    if ( self::isNginxHandlingImages() && ( isset( $_GET['source'] ) || isset( $_GET['xsource'] ) ) ) {
        self::$checking = 'source (passed as absolute path on nginx)';
        if ( isset( $_GET['source'] ) ) {
            $source = SanityCheck::absPathExistsAndIsFile( wp_unslash( $_GET['source'] ) );
        } else {
            $xsrc  = SanityCheck::noControlChars( wp_unslash( $_GET['xsource'] ) );
            return SanityCheck::absPathExistsAndIsFile( substr( $xsrc, 1 ) );
        }
    }

    // Last resort: use REQUEST_URI.
    if ( isset( self::$docRoot ) ) {
        self::$checking = 'source (retrieved by the request_uri server var)';
        $src_rel = SanityCheck::pathWithoutDirectoryTraversal( parse_url( wp_unslash( $_SERVER['REQUEST_URI'] ), PHP_URL_PATH ) );
        return SanityCheck::absPathExistsAndIsFile( self::$docRoot . $src_rel );
    }

    return false;
}

