/**
 * Gets a request parameter value without sanitization (caller must sanitize).
 *
 * @param string       $key    The request key to retrieve.
 * @param mixed        $def    Default value when key is not set.
 * @param string|false $type   Request type: 'post', 'get', or false for $_REQUEST.
 * @return mixed The raw (unslashed) value or $def if not set.
 */
function fs_request_get_raw( $key, $def = false, $type = false ) {
    $safe_key = sanitize_key( $key );

    if ( is_string( $type ) ) {
        $type = strtolower( $type );
    }

    switch ( $type ) {
        case 'post':
            $value = isset( $_POST[ $safe_key ] ) ? $_POST[ $safe_key ] : $def;
            break;
        case 'get':
            $value = isset( $_GET[ $safe_key ] ) ? $_GET[ $safe_key ] : $def;
            break;
        default:
            $value = isset( $_REQUEST[ $safe_key ] ) ? $_REQUEST[ $safe_key ] : $def;
            break;
    }

    return empty( $value ) ? $value : wp_unslash( $value );
}

