	 *
	 * @since 6.2
	 *
	 * @param string $key  The key to get paths for (optional).
	 * @param array  $post The main ACF post array (optional).
	 * @return array
	 */
function get_save_paths( $key = '', $post = array() ) {
		$name      = ! empty( $post['title'] ) ? (string) $post['title'] : '';
		$post_type = acf_determine_internal_post_type( $key );
		$paths     = array();
		$safe_key  = sanitize_key( $key );

		// Paths are sorted by priority, with key overriding name, etc.
		if ( $safe_key ) {
			$paths[] = acf_get_setting( "save_json/key={$safe_key}" );
		}

		if ( $name ) {
			$paths[] = acf_get_setting( 'save_json/name=' . sanitize_title( $name ) );
		}

		if ( $post_type ) {
			$paths[] = acf_get_setting( 'save_json/post_type=' . sanitize_key( $post_type ) );
		}

		$paths   = array_filter( $paths );
		$paths[] = acf_get_setting( 'save_json' );

		return apply_filters( 'acf/json/save_paths', $paths, $key, $post );
	}

