/**
	 * Validate reCAPTCHA v3 token against Google API.
	 *
	 * @since 1.0.0
	 *
	 * @param string $name    Field name being validated.
	 * @param array  $options Validation options including 'secret_key' and 'score_threshold'.
	 * @return bool|WP_Error True on success, WP_Error on failure.
	 */
function rule( $name, array $options = array() ) {
		$token      = isset( $_POST['g-recaptcha-response'] ) ? sanitize_text_field( wp_unslash( $_POST['g-recaptcha-response'] ) ) : '';
		$secret_key = isset( $options['secret_key'] ) ? $options['secret_key'] : '';

		if ( empty( $token ) || empty( $secret_key ) ) {
			return new WP_Error( 'recaptcha_missing', __( 'reCAPTCHA verification failed.', 'recaptcha-for-mw-wp-form' ) );
		}

		$url      = 'https://www.google.com/recaptcha/api/siteverify';
		$response = wp_remote_post(
			$url,
			array(
				'body' => array(
					'secret'   => $secret_key,
					'response' => $token,
				),
			)
		);

		if ( is_wp_error( $response ) ) {
			return new WP_Error( 'recaptcha_request_failed', __( 'reCAPTCHA request failed.', 'recaptcha-for-mw-wp-form' ) );
		}

		$body   = json_decode( wp_remote_retrieve_body( $response ), true );
		$score  = isset( $body['score'] ) ? (float) $body['score'] : 0.0;
		$thresh = isset( $options['score_threshold'] ) ? (float) $options['score_threshold'] : 0.5;

		if ( ! isset( $body['success'] ) || true !== $body['success'] || $score < $thresh ) {
			return new WP_Error( 'recaptcha_failed', __( 'reCAPTCHA verification failed.', 'recaptcha-for-mw-wp-form' ) );
		}

		return true;
	}

