/**
	 * Cleans orphaned rows from a yoast table.
	 *
	 * @param string $table  The table to clean up.
	 * @param string $column The table column the cleanup will rely on.
	 * @param int    $limit  The limit we'll apply to the queries.
	 *
	 * @return int|bool The number of deleted rows, false if the query fails.
	 */
function cleanup_orphaned_from_table( string $table, string $column, int $limit ) {
		global $wpdb;

		$allowed_columns = array( 'id', 'indexable_id', 'object_id' );
		if ( ! in_array( $column, $allowed_columns, true ) ) {
			return false;
		}

		$table           = Model::get_table_name( $table );
		$indexable_table = Model::get_table_name( 'Indexable' );

		// Warning: If this query is changed, make sure to update the query in cleanup_orphaned_from_table in Premium as well.
		// phpcs:disable WordPress.DB.PreparedSQL.InterpolatedNotPrepared -- Reason: $column is whitelisted above.
		$query = $wpdb->prepare(
			"
			SELECT table_to_clean.{$column}
			FROM {$table} AS table_to_clean
			LEFT JOIN {$indexable_table} AS indexable
				ON table_to_clean.{$column} = indexable.id
			WHERE indexable.id IS NULL
			LIMIT %d",
			$limit
		);
		// phpcs:enable WordPress.DB.PreparedSQL.InterpolatedNotPrepared

		$ids = $wpdb->get_col( $query );

		if ( empty( $ids ) ) {
			return 0;
		}

		$placeholders = implode( ', ', array_fill( 0, count( $ids ), '%d' ) );
		// phpcs:disable WordPress.DB.PreparedSQL.NotPrepared -- Reason: placeholders built from count only.
		$delete_query = $wpdb->prepare(
			"DELETE FROM {$table} WHERE {$column} IN ( {$placeholders} )",
			$ids
		);
		// phpcs:enable WordPress.DB.PreparedSQL.NotPrepared

		return $wpdb->query( $delete_query );
	}

