function check_cacheability( \WP_Query $wp_query ) {
		$this->is_cacheable = true;

		$rules = Settings::get_option( $this->options, 'excluded', [] );
		if ( $rules ) {
			$rewriter = Rewriter::getInstance();
			foreach ( array_filter( $rules ) as $rule ) {
				if ( $rewriter->match( $rule ) ) {
					$this->is_cacheable = false;
					return;
				}
			}
		}

		$request_method = sanitize_key( wp_unslash( $_SERVER['REQUEST_METHOD'] ?? 'GET' ) );

		if ( is_user_logged_in() ) {
			$this->is_cacheable = false;
		} elseif ( $wp_query->is_admin || is_login() || $wp_query->is_robots || $wp_query->is_feed || $wp_query->is_comment_feed || $wp_query->is_preview ) {
			$this->is_cacheable = false;
		} elseif ( wp_doing_ajax() || wp_doing_cron() ) {
			$this->is_cacheable = false;
		} elseif ( defined( 'DONOTCACHEPAGE' ) || ( defined( 'WPOPT_DISABLE_CACHE' ) && WPOPT_DISABLE_CACHE ) ) {
			$this->is_cacheable = false;
		} elseif ( 'GET' !== $request_method ) {
			$this->is_cacheable = false;
		} elseif ( isset( $_GET['preview'] ) || isset( $_GET['s'] ) ) {
			$this->is_cacheable = false;
		}

		$this->is_cacheable = apply_filters( 'wpopt_allow_static_cache', $this->is_cacheable, $wp_query );
	}

