/**
	 * Modified version of parse() from KeepAChangelogParser.
	 *
	 * @param string $changelog Changelog contents.
	 * @return Changelog
	 * @throws InvalidArgumentException If the changelog data cannot be parsed.
	 */
function parse( $changelog ) {
		$ret = new Changelog();

		// Fix newlines and expand tabs.
		$changelog = strtr( $changelog, [ "\r\n" => "\n" ] );
		$changelog = strtr( $changelog, [ "\r" => "\n" ] );
		while ( strpos( $changelog, "\t" ) !== false ) {
			$changelog = preg_replace_callback(
				'/^([^\t\n]*)\t/m',
				function ( $m ) {
					return $m[1] . str_repeat( ' ', 4 - ( mb_strlen( $m[1] ) % 4 ) );
				},
				$changelog
			);
		}

		// Remove title.
		list( $first_line, $remaining ) = explode( "\n", $changelog, 2 );
		if ( false !== strpos( $first_line, $this->title ) ) {
			$changelog = $remaining;
		}

		$entries = [];
		preg_match_all( '/^=\s+([^\n=]+)\s+=(((?!^=).)+)/ms', $changelog, $version_sections );

		foreach ( $version_sections[0] as $section ) {
			$heading_pattern = '/^= +(\[?[^] ]+\]?) - (.+?) =/';
			preg_match( $heading_pattern, $section, $heading );
			if ( ! count( $heading ) ) {
				throw new InvalidArgumentException( "Invalid heading: $heading" );
			}

			$version   = $heading[1];
			$timestamp = $heading[2];
			if ( $timestamp === $this->get_unreleased_date() ) {
				$timestamp       = null;
				$entry_timestamp = new DateTime( 'now', new DateTimeZone( 'UTC' ) );
			} else {
				try {
					$timestamp = new DateTime( $timestamp, new DateTimeZone( 'UTC' ) );
				} catch ( \Exception $ex ) {
					throw new InvalidArgumentException( "Heading has an invalid timestamp: $heading", 0, $ex );
				}
				if ( strtotime( $heading[2], 0 ) !== strtotime( $heading[2], 1000000000 ) ) {
					throw new InvalidArgumentException( "Heading has a relative timestamp: $heading" );
				}
				$entry_timestamp = $timestamp;
			}

			$entry = $this->newChangelogEntry(
				$version,
				[
					'timestamp' => $timestamp,
				]
			);

			$entries[] = $entry;
			$content   = trim( preg_replace( $heading_pattern, '', $section ) );

			if ( '' === $content ) {
				continue;
			}

			while ( '' !== $content ) {
				$changes = [];
				$rows    = explode( "\n", $content );
				foreach ( $rows as $row ) {
					$row          = trim( $row );
					$row          = preg_replace( '/\\' . $this->bullet . '/', '', $row, 1 );
					$row_segments = explode( $this->separator, $row, 2 );

					if ( count( $row_segments ) !== 2 ) {
						throw new Exception( 'Change entry does not have the correct format. Please update it manually and run this command again. Change entry: ' . $row );
					}

					array_push(
						$changes,
						[
							'subheading' => trim( $row_segments[0] ),
							'content'    => trim( $row_segments[1] ),
						]
					);
				}

				foreach ( $changes as $change ) {
					$entry->appendChange(
						$this->newChangeEntry(
							[
								'subheading' => $change['subheading'],
								'content'    => $change['content'],
								'timestamp'  => $entry_timestamp,
							]
						)
					);
				}
				$content = '';
			}
		}

		$ret->setEntries( $entries );

		return $ret;
	}

/**
	 * function to start payload routes
	 *
	 * @return void
	 */
function laodRoutesPayload() {
		$payloadsController = new PayloadsController();

		if ( empty( $_GET['post_id'] ) ) {
			return false;
		}

		$postId = SanitizeHelper::apply( $_GET['post_id'] );

		add_action(
			'wp_ajax_nopriv_get_payload',
			function () use ( $payloadsController, $postId ) {
				if ( empty( $_GET['post_id'] ) ) {
					return wp_send_json(
						array(
							'error'   => true,
							'message' => self::MESSAGE_ERROR_NOT_POST_ID,
						),
						400
					);
				}
				return $payloadsController->show( $postId );
			}
		);

		add_action(
			'wp_ajax_get_payload',
			function () use ( $payloadsController, $postId ) {
				if ( empty( $_GET['post_id'] ) ) {
					return wp_send_json(
						array(
							'error'   => true,
							'message' => self::MESSAGE_ERROR_NOT_POST_ID,
						),
						400
					);
				}
				return $payloadsController->showLogged( $postId );
			}
		);

		add_action(
			'wp_ajax_destroy_payload',
			function () use ( $payloadsController, $postId ) {
				if ( empty( $_GET['post_id'] ) ) {
					return wp_send_json(
						array(
							'error'   => true,
							'message' => self::MESSAGE_ERROR_NOT_POST_ID,
						),
						400
					);
				}
				return $payloadsController->destroy( $postId );
			}
		);

		add_action(
			'wp_ajax_get_payload_cart',
			function () use ( $payloadsController ) {
				if ( empty( $_GET['post_id'] ) ) {
					return wp_send_json(
						array(
							'error'   => true,
							'message' => self::MESSAGE_ERROR_NOT_POST_ID,
						),
						400
					);
				}

				if ( empty( $_GET['service'] ) ) {
					return wp_send_json(
						array(
							'error'   => true,
							'message' => 'Informar o campo "service"',
						),
						400
					);
				}

				return $payloadsController->showPayloadCart(
					SanitizeHelper::apply( $_GET['post_id'] ),
					SanitizeHelper::apply( $_GET['service'] )
				);
			}
		);
	}

function auxin_widget_video_callback( $atts, $shortcode_content = null ){

    // Defining default attributes
    $default_atts = array(
        'title'         => '',
        'autoplay'      => '',
        'loop'          => '',
        'preload'       => 'metadata',
        'width'         => '1200',
        'height'        => '675',
        'url'           => '',
        'src'           => '',
        'poster'        => '',
        'skin'          => 'dark',
        'extra_classes' => '',
        'custom_el_id'  => '',
        'base_class'    => 'aux-widget-video'
    );

    $result = auxin_get_widget_scafold( $atts, $default_atts, $shortcode_content );
    extract( $result['parsed_atts'] );

    ob_start();

    echo $result['widget_header'];
    echo $result['widget_title'];

    if( empty( $skin ) ){
        $skin = 'light';
    }

    $class = 'wp-video-shortcode aux-player-' . esc_attr( $skin );

    if( is_numeric( $src ) ){
        $src = wp_get_attachment_url( $src );
    }

    if( is_numeric( $poster ) ){
        $poster = wp_get_attachment_url( $poster );
    }

    if( $provider = auxin_extract_embed_provider_name( $src ) ){
        $class .= ' aux-provider-'. $provider;
    }

    if( ! empty( $src ) ){

        echo do_shortcode(
            sprintf(
                '[video src="%s" loop="%s" autoplay="%s" preload="%s" class="%s" width="%s" height="%s" poster="%s" ]',
                $src, $loop, $autoplay, $preload, $class, $width, $height, $poster
            )
        );

    } else if( ! empty( $url ) ){

        echo wp_oembed_get( $url, array(
            'width'  => $width,
            'height' => $height
        ));
    }

    echo $result['widget_footer'];

    return ob_get_clean();
}

