function auxin_widget_divider_callback( $atts, $shortcode_content = null ){

    $default_atts = array(
        'title'         => '',
        'size'          => '',
        'style'         => 'solid',
        'width'         => 'medium',
        'base_class'    => '',
        'margin_bottom' => '',
        'margin_top'    => '',
        'extra_classes' => '',
        'custom_el_id'  => '',
        'base_class'    => 'aux-widget-divider'
    );

    $result = auxin_get_widget_scafold( $atts, $default_atts, $shortcode_content );
    extract( $result['parsed_atts'] );

    $class_names = "";
    $inline_styles = "";

    switch ($style) {
        case 'solid': $class_names = "aux-divider-center"; break;
        case 'dashed': $class_names = "aux-divider-dashed"; break;
        case 'circle-symbol': $class_names = "aux-divider-symbolic-circle"; break;
        case 'diamond-symbol': $class_names = "aux-divider-symbolic-square"; break;
        case 'white-space': $class_names = "aux-divider-space"; break;
    }

    switch ($width) {
        case 'large': $class_names .= ""; break;
        case 'medium': $class_names .= " aux-divider-medium"; break;
        case 'small': $class_names .= " aux-divider-small"; break;
    }

    if( ! empty( $extra_classes ) ) { $class_names .= " $extra_classes"; }
    if( ! empty( $margin_top ) ) { $margin_top = (int)$margin_top; $inline_styles .= "margin-top: $margin_top" . "px;"; }
    if( ! empty( $margin_bottom ) ) { $margin_bottom = (int)$margin_bottom; $inline_styles .= "margin-bottom:$margin_bottom" . "px;"; }
    if( ! empty( $inline_styles ) ) { $inline_styles = ' style="' . $inline_styles . '" '; }

    return '<hr class="'. $class_names . '"' . $inline_styles . ' >';
}

